const deliveryWindow=()=>{const a=new Date(),b=new Date();a.setDate(a.getDate()+1);b.setDate(b.getDate()+3);const f=d=>d.toLocaleDateString('ru-RU',{day:'numeric',month:'short'}).replace('.','');return `${f(a)} — ${f(b)}`};
const productOptions=p=>{
  if(p.cat==='Обувь')return {label:tr('shoeSize'),values:['36','37','38','39','40','41'],guide:'shoes'};
  if(['Сумки','Аксессуары'].includes(p.cat))return {label:null,values:[],defaultValue:'ONE SIZE'};
  if(p.sizeValues)return {label:tr('size'),values:p.sizeValues.map(String),guide:p.sizeGuide||'eu'};
  return {label:tr('size'),values:sizes,guide:'clothing'};
};
